struct CoolingCrystallizerYieldEngine: Sendable { func calculate(_ input: CoolingCrystallizerYieldInput) throws -> CoolingCrystallizerYieldResult { let v=[input.solventMass,input.hotSolubility,input.coldSolubility,input.crystalPurityFraction]; guard v.allSatisfy(\.isFinite) else { throw CoolingCrystallizerYieldError.nonFiniteInput }; guard input.solventMass>0 else { throw CoolingCrystallizerYieldError.nonPositiveSolventMass }; guard input.hotSolubility>input.coldSolubility,input.coldSolubility>=0 else { throw CoolingCrystallizerYieldError.invalidSolubility }; guard input.crystalPurityFraction>0,input.crystalPurityFraction<=1 else { throw CoolingCrystallizerYieldError.invalidPurity }; let i=input.solventMass*input.hotSolubility; let f=input.solventMass*input.coldSolubility; let c=i-f; let p=c/input.crystalPurityFraction; let r=c/i; guard [i,f,c,p,r].allSatisfy(\.isFinite),r>0,r<1 else { throw CoolingCrystallizerYieldError.numericalFailure }; return .init(initialDissolvedSolute:i,finalDissolvedSolute:f,pureCrystalMass:c,recoveredCrystalProduct:p,soluteRecoveryFraction:r,modelName:"Cooling crystallization solubility balance",limitationDescription:"Solvent loss and mother-liquor entrainment are neglected.") } }
